import {
  createContext,
  useContext,
  useEffect,
  useId,
  useRef,
  type HTMLAttributes,
  type ReactNode,
} from 'react';
import { createPortal } from 'react-dom';
import { cn, vc } from '../../utils/cn';
import styles from './Modal.module.css';

// -------------------- Context --------------------

interface ModalContextValue {
  onClose: () => void;
  titleId: string;
  size: ModalSize;
}
const ModalContext = createContext<ModalContextValue | null>(null);
const useModalContext = () => {
  const ctx = useContext(ModalContext);
  if (!ctx) throw new Error('Modal.* must be used inside <Modal>');
  return ctx;
};

// -------------------- Types --------------------

export type ModalSize = 'sm' | 'md' | 'lg' | 'fullscreen';

export interface ModalProps {
  open: boolean;
  onClose: () => void;
  title?: string;
  size?: ModalSize;
  closeOnBackdrop?: boolean;
  closeOnEscape?: boolean;
  children?: ReactNode;
  className?: string;
}

// -------------------- Root --------------------

function ModalRoot({
  open,
  onClose,
  title,
  size = 'md',
  closeOnBackdrop = true,
  closeOnEscape = true,
  children,
  className,
}: ModalProps) {
  const titleId = useId();
  const contentRef = useRef<HTMLDivElement | null>(null);
  const previouslyFocused = useRef<HTMLElement | null>(null);

  // Trap focus + auto-focus first focusable + return focus on close.
  useEffect(() => {
    if (!open) return;
    previouslyFocused.current = document.activeElement as HTMLElement | null;
    const content = contentRef.current;
    if (!content) return;

    const focusable = content.querySelectorAll<HTMLElement>(
      'a[href], button:not([disabled]), textarea:not([disabled]), input:not([disabled]), select:not([disabled]), [tabindex]:not([tabindex="-1"])',
    );
    (focusable[0] ?? content).focus();

    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && closeOnEscape) {
        e.stopPropagation();
        onClose();
      } else if (e.key === 'Tab') {
        const nodes = content.querySelectorAll<HTMLElement>(
          'a[href], button:not([disabled]), textarea:not([disabled]), input:not([disabled]), select:not([disabled]), [tabindex]:not([tabindex="-1"])',
        );
        if (nodes.length === 0) return;
        const first = nodes[0];
        const last = nodes[nodes.length - 1];
        if (e.shiftKey && document.activeElement === first) {
          e.preventDefault();
          last.focus();
        } else if (!e.shiftKey && document.activeElement === last) {
          e.preventDefault();
          first.focus();
        }
      }
    };
    document.addEventListener('keydown', onKey);
    return () => {
      document.removeEventListener('keydown', onKey);
      previouslyFocused.current?.focus?.();
    };
  }, [open, onClose, closeOnEscape]);

  // Scroll lock.
  useEffect(() => {
    if (!open) return;
    const prev = document.body.style.overflow;
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = prev;
    };
  }, [open]);

  if (!open || typeof document === 'undefined') return null;

  const handleBackdrop = () => {
    if (closeOnBackdrop) onClose();
  };

  return createPortal(
    <ModalContext.Provider value={{ onClose, titleId, size }}>
      <div
        className={styles.backdrop}
        onClick={handleBackdrop}
        data-testid="tatva-modal-backdrop"
      >
        <div
          ref={contentRef}
          role="dialog"
          aria-modal="true"
          aria-labelledby={title ? titleId : undefined}
          tabIndex={-1}
          className={cn(styles.content, vc(styles, 'size', size), className)}
          onClick={(e) => e.stopPropagation()}
          data-testid="tatva-modal"
        >
          {title && (
            <ModalHeaderInternal>
              <h2 id={titleId} className={styles.title}>
                {title}
              </h2>
            </ModalHeaderInternal>
          )}
          {children}
        </div>
      </div>
    </ModalContext.Provider>,
    document.body,
  );
}

// -------------------- Sub-components --------------------

function ModalHeaderInternal({ children }: { children: ReactNode }) {
  const { onClose } = useModalContext();
  return (
    <div className={styles.header}>
      <div className={styles.headerContent}>{children}</div>
      <button
        type="button"
        className={styles.close}
        onClick={onClose}
        aria-label="Close"
      >
        ×
      </button>
    </div>
  );
}

function ModalHeader({
  children,
  className,
  ...rest
}: HTMLAttributes<HTMLDivElement>) {
  return (
    <ModalHeaderInternal>
      <div className={cn(styles.headerContent, className)} {...rest}>
        {children}
      </div>
    </ModalHeaderInternal>
  );
}

function ModalBody({
  className,
  children,
  ...rest
}: HTMLAttributes<HTMLDivElement>) {
  return (
    <div className={cn(styles.body, className)} {...rest}>
      {children}
    </div>
  );
}

function ModalFooter({
  className,
  children,
  ...rest
}: HTMLAttributes<HTMLDivElement>) {
  return (
    <div className={cn(styles.footer, className)} {...rest}>
      {children}
    </div>
  );
}

/**
 * Modal — accessible dialog with backdrop, focus trap, scroll lock.
 * Compound API: `<Modal><Modal.Header/><Modal.Body/><Modal.Footer/></Modal>`.
 */
export const Modal = Object.assign(ModalRoot, {
  Header: ModalHeader,
  Body: ModalBody,
  Footer: ModalFooter,
});

.backdrop {
  position: fixed;
  inset: 0;
  background-color: var(--tatva-color-overlay);
  z-index: var(--tatva-z-modal);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: var(--tatva-space-4);
  animation: tatva-modal-backdrop-in 200ms ease;
}

.content {
  background-color: var(--tatva-color-bg);
  color: var(--tatva-color-fg);
  border-radius: var(--tatva-radius-xl);
  box-shadow: var(--tatva-shadow-xl);
  width: 100%;
  max-height: calc(100vh - 2 * var(--tatva-space-4));
  display: flex;
  flex-direction: column;
  outline: none;
  overflow: hidden;
  animation: tatva-modal-content-in 200ms ease;
  font-family: var(--tatva-font-family);
}

.sizeSm { max-width: 400px; }
.sizeMd { max-width: 560px; }
.sizeLg { max-width: 720px; }
.sizeFullscreen {
  max-width: none;
  width: 100vw;
  height: 100vh;
  max-height: 100vh;
  border-radius: 0;
}

.header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--tatva-space-4);
  border-bottom: 1px solid var(--tatva-color-border);
  gap: var(--tatva-space-3);
  flex: 0 0 auto;
}

.headerContent {
  flex: 1;
  min-width: 0;
}

.title {
  font-size: var(--tatva-font-size-lg);
  font-weight: var(--tatva-font-weight-semibold);
  margin: 0;
}

.close {
  background: transparent;
  border: none;
  font-size: 24px;
  line-height: 1;
  color: var(--tatva-color-fg-muted);
  cursor: pointer;
  padding: var(--tatva-space-1);
  border-radius: var(--tatva-radius-sm);
}
.close:hover {
  background-color: var(--tatva-color-neutral-100);
  color: var(--tatva-color-fg);
}
.close:focus-visible {
  outline: none;
  box-shadow: 0 0 0 3px var(--tatva-color-primary-200);
}

.body {
  padding: var(--tatva-space-4);
  overflow-y: auto;
  flex: 1 1 auto;
}

.footer {
  display: flex;
  justify-content: flex-end;
  gap: var(--tatva-space-2);
  padding: var(--tatva-space-4);
  border-top: 1px solid var(--tatva-color-border);
  flex: 0 0 auto;
}

@keyframes tatva-modal-backdrop-in {
  from { opacity: 0; }
  to { opacity: 1; }
}
@keyframes tatva-modal-content-in {
  from { opacity: 0; transform: scale(0.96); }
  to { opacity: 1; transform: scale(1); }
}
